CSS=r'''
@font-face{font-family:Prompt;src:url('assets/font-black.ttf') format('truetype');font-weight:900}
@font-face{font-family:Prompt;src:url('assets/font-bold.ttf') format('truetype');font-weight:700}
@font-face{font-family:Prompt;src:url('assets/font-regular.ttf') format('truetype');font-weight:400}
:root{--pink:#E91451;--deep:#740A28;--black:#0A0A0A;--white:#fff}*{box-sizing:border-box}body{margin:0;background:#111;font-family:Prompt,Arial,sans-serif}.post{width:1080px;height:1350px;position:relative;overflow:hidden;background:#0A0A0A;color:#fff}.photo{position:absolute;inset:0;z-index:1}.photo img{width:100%;height:100%;object-fit:cover;object-position:center center;filter:contrast(1.12) saturate(1.13) brightness(1.13)}.fade{position:absolute;inset:0;z-index:2;background:linear-gradient(90deg,rgba(0,0,0,.84),rgba(0,0,0,.44) 36%,rgba(0,0,0,.06) 69%),linear-gradient(180deg,rgba(0,0,0,.68),rgba(0,0,0,.05) 32%,rgba(0,0,0,.92));pointer-events:none}.glow{position:absolute;inset:0;z-index:3;background:radial-gradient(ellipse at 18% 30%,rgba(233,20,81,.38),transparent 32%),radial-gradient(ellipse at 70% 76%,rgba(233,20,81,.18),transparent 36%);mix-blend-mode:screen}.halftone{position:absolute;inset:0;z-index:4;background-image:radial-gradient(circle,var(--pink) 2.1px,transparent 3.3px);background-size:18px 18px;opacity:.24;mix-blend-mode:screen;mask-image:linear-gradient(to right,black 0%,black 25%,transparent 56%);-webkit-mask-image:linear-gradient(to right,black 0%,black 25%,transparent 56%)}.logo{position:absolute;top:54px;left:0;right:0;display:flex;justify-content:center;z-index:20;filter:drop-shadow(0 7px 15px rgba(0,0,0,.95))}.logo img{height:78px;max-width:360px}.la{position:absolute;left:-255px;bottom:80px;width:620px;height:620px;z-index:5;opacity:.10;transform:rotate(-12deg);pointer-events:none}.la img{width:100%;height:100%;object-fit:contain}.content{position:absolute;z-index:10;left:66px;top:205px;width:585px}.kicker{display:inline-flex;align-items:center;gap:14px;font-size:24px;font-weight:900;letter-spacing:3px;text-transform:uppercase;color:#fff;margin-bottom:22px;text-shadow:0 4px 14px #000}.kicker:before{content:'';display:block;width:54px;height:6px;background:var(--pink);transform:skewX(-25deg)}h1{margin:0;font-weight:900;text-transform:uppercase;letter-spacing:-6px;font-size:112px;line-height:.80;text-shadow:0 8px 24px rgba(0,0,0,.98)}.outline{color:transparent;-webkit-text-stroke:4px #fff;text-shadow:0 5px 18px #000}.pink{color:var(--pink)}.body{margin-top:24px;font-size:45px;line-height:1.04;font-weight:700;text-shadow:0 7px 22px #000,0 0 6px #000}.sticker{display:inline-block;margin-top:26px;background:var(--pink);color:#fff;border-radius:999px;padding:14px 28px;font-size:25px;font-weight:900;text-transform:uppercase;letter-spacing:1.6px;box-shadow:7px 8px 0 rgba(0,0,0,.75)}.footer{position:absolute;bottom:48px;left:0;right:0;display:flex;flex-direction:column;align-items:center;z-index:25}.pill{display:inline-flex;align-items:center;gap:13px;background:var(--pink);color:#fff;padding:17px 36px;border-radius:999px;font-weight:900;font-size:23px;text-transform:uppercase;letter-spacing:1.4px;box-shadow:6px 7px 0 rgba(0,0,0,.75)}.ig{width:25px;height:25px;border:2px solid #fff;border-radius:6px;position:relative}.ig:after{content:'';position:absolute;top:50%;left:50%;width:8px;height:8px;border:2px solid #fff;border-radius:50%;transform:translate(-50%,-50%)}.stripes{display:flex;gap:8px;margin-top:12px}.stripes i{display:block;width:36px;height:7px;background:#fff;transform:skewX(-25deg)}.slashes{position:absolute;left:66px;bottom:152px;display:flex;gap:9px;z-index:9}.slashes i{display:block;width:42px;height:9px;background:var(--pink);transform:skewX(-25deg)}
'''
html=f"""<!doctype html><html><head><meta charset='utf-8'><style>{CSS}</style></head><body><section class='post'><div class='photo'><img src='assets/photo.jpg'></div><div class='fade'></div><div class='glow'></div><div style='position:absolute;inset:0;z-index:3;background:radial-gradient(ellipse at 71% 42%,rgba(255,235,235,.13),transparent 22%),radial-gradient(ellipse at 72% 72%,rgba(255,235,235,.08),transparent 20%);mix-blend-mode:screen;pointer-events:none'></div><div class='halftone'></div><div class='la'><img src='assets/la-solo.svg'></div><div class='logo'><img src='assets/logo-dark.svg'></div><div class='content'><div class='kicker'>aluna em palco</div><h1>O PALCO<br><span class='outline'>COMEÇA</span><br><span class='pink'>AQUI</span></h1><div class='body'>Quando a aula vira coragem, o som ganha presença.</div><div class='sticker'>LA Music School</div></div><div class='slashes'><i></i><i></i><i></i><i></i></div><div class='footer'><div class='pill'><span class='ig'></span>@lamusicschool</div><div class='stripes'><i></i><i></i><i></i><i></i></div></div></section></body></html>"""
