subprocess.run(['/usr/local/bin/chromium','--headless','--no-sandbox','--disable-gpu','--window-size=1080,1350',f'--screenshot={OUT/"la-school-o-palco-comeca-aqui.png"}',(OUT/'post.html').as_uri()],check=True,stdout=subprocess.PIPE,stderr=subprocess.PIPE)
(OUT/'LAHQ_PIPELINE.md').write_text('''# LA Music School — Arte única feed\n\nTema: O palco começa aqui\nFoto real: aluna no teclado em performance\nFormato: 1080x1350\nSkill: lahq-school-content\n\nDireção: design no padrão V4 manifesto, mas peça única. Texto em área segura à esquerda, sem cobrir rosto/teclado.\nCopy: manifesto curto — aula vira coragem, som ganha presença.\n''')
